// Bundled white PNG icon set (pre-rasterized, embeds in the worker with no DOM). icon(name) → data URI;
// the model drops it in via s.addImage({ data: helpers.icon("chip"), x,y,w,h }) — best on a coloured badge.
const PNG = {"chip":"","cloud":"","shield":"","lock":"","bolt":"","bar":"","trending":"","gear":"","users":"","database":"","server":"","globe":"","rocket":"","brain":"","check":"","alert":"","target":"","layers":"","building":"","dollar":"","star":"","arrow":"","dot":""};
const ALIAS = {"cpu":"chip","ai":"brain","security":"shield","chart":"bar","growth":"trending","settings":"gear","people":"users","team":"users","data":"database","network":"globe","money":"dollar","warning":"alert","success":"check","company":"building","stack":"layers"};
export const ICON_NAMES = Object.keys(PNG).filter((k) => k !== "dot").concat(Object.keys(ALIAS));
export function icon(name) {
  const key = String(name || "").toLowerCase().trim();
  const b64 = PNG[key] || PNG[ALIAS[key]] || PNG.dot;
  return "data:image/png;base64," + b64;
}
